       "tokenizer": AutoTokenizer,
       "pipeline": ImageTextToTextPipeline,
       "model": AutoModelForVision2Seq,  // or appropriate model type
       "processor": AutoProcessor,
       "default": {
           "model": "Xenova/appropriate-model",
