/**
 * Image-text-to-text pipeline using any `AutoModelForImageTextToText`. This pipeline generates
 * text from an image and a text prompt, and is designed for vision-language models such as
 * LLaVA, SmolVLM, PaliGemma, and Qwen2-VL.
 *
 * **Example:** Generate text from an image and a prompt w/ `HuggingFaceTB/SmolVLM-256M-Instruct`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'HuggingFaceTB/SmolVLM-256M-Instruct');
 * const image = 'https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/transformers/tasks/car.jpg';
 * const output = await pipe(image, 'What is in this image?');
 * // [{ generated_text: 'A blue car parked on a street.' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(images, text, generate_kwargs = {}) {

        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        if (!Array.isArray(text)) {
            text = new Array(preparedImages.length).fill(text);
        }

        // The processor handles combining text prompts and images into model inputs
        // (e.g., inserting image tokens, tokenizing text, extracting pixel values)
        const inputs = await this.processor(text, preparedImages);

        const output = await this.model.generate({ ...inputs, ...generate_kwargs });

        const decoded = this.tokenizer.batch_decode(/** @type {Tensor} */(output), {
            skip_special_tokens: true,
        }).map(x => ({ generated_text: x }));

        // Single input  → [{ generated_text }]
        // Batched input → [[{ generated_text }], [{ generated_text }], ...]
        return isBatched ? decoded.map(x => [x]) : decoded;
    }
}

